#!/usr/bin/env python3
import base64, os, subprocess

b64_server = ""
os.makedirs(os.path.dirname("/var/www/konverta/server.js"), exist_ok=True)
open("/var/www/konverta/server.js", "wb").write(base64.b64decode(b64_server))
print("✓ /var/www/konverta/server.js")

b64_auth = ""
os.makedirs(os.path.dirname("/var/www/konverta/src/routes/auth.js"), exist_ok=True)
open("/var/www/konverta/src/routes/auth.js", "wb").write(base64.b64decode(b64_auth))
print("✓ /var/www/konverta/src/routes/auth.js")

b64_events = ""
os.makedirs(os.path.dirname("/var/www/konverta/src/routes/events.js"), exist_ok=True)
open("/var/www/konverta/src/routes/events.js", "wb").write(base64.b64decode(b64_events))
print("✓ /var/www/konverta/src/routes/events.js")

b64_origin = ""
os.makedirs(os.path.dirname("/var/www/konverta/src/origin-check.js"), exist_ok=True)
open("/var/www/konverta/src/origin-check.js", "wb").write(base64.b64decode(b64_origin))
print("✓ /var/www/konverta/src/origin-check.js")

b64_admin_html = ""
os.makedirs(os.path.dirname("/var/www/konverta/public/admin.html"), exist_ok=True)
open("/var/www/konverta/public/admin.html", "wb").write(base64.b64decode(b64_admin_html))
print("✓ /var/www/konverta/public/admin.html")

b64_pkgjson = ""
os.makedirs(os.path.dirname("/var/www/konverta/package.json"), exist_ok=True)
open("/var/www/konverta/package.json", "wb").write(base64.b64decode(b64_pkgjson))
print("✓ /var/www/konverta/package.json")

# Instala nova dependencia @fastify/cookie
print("\nInstalando @fastify/cookie...")
subprocess.run(["npm", "install"], cwd="/var/www/konverta")

# Adiciona ADMIN_USER ao .env se não existir

try:
    env = open("/var/www/konverta/.env").read()
    if "ADMIN_USER" not in env:
        open("/var/www/konverta/.env", "a").write("\nADMIN_USER=admin\n")
        print("✓ ADMIN_USER=admin adicionado ao .env")
    else:
        print("✓ ADMIN_USER já existe no .env")
except: pass

print("\n✅ Tudo atualizado!")
subprocess.run(["pm2", "restart", "konverta"])